package positionsmath

import (
	"sort"
	"time"
)

// UserHolder is for sorting only—combines valuation and earliest bet.
type UserHolder struct {
	Username     string
	RoundedValue int64
	EarliestBet  time.Time
}

type ByValBetTimeUsername []UserHolder

func (s ByValBetTimeUsername) Len() int      { return len(s) }
func (s ByValBetTimeUsername) Swap(i, j int) { s[i], s[j] = s[j], s[i] }
func (s ByValBetTimeUsername) Less(i, j int) bool {
	if s[i].RoundedValue != s[j].RoundedValue {
		return s[i].RoundedValue > s[j].RoundedValue
	}
	if !s[i].EarliestBet.Equal(s[j].EarliestBet) {
		return s[i].EarliestBet.Before(s[j].EarliestBet)
	}
	return s[i].Username < s[j].Username
}

// AdjustUserValuationsToMarketVolume ensures user values match total market volume,
// distributing rounding delta deterministically. Only users with >0 value are adjusted.
func AdjustUserValuationsToMarketVolume(
	userValuations map[string]UserValuationResult,
	earliestBets map[string]time.Time,
	targetMarketVolume int64,
) map[string]UserValuationResult {
	// Filter out users with zero valuation
	filtered := filterWinningValuations(userValuations)
	if len(filtered) == 0 {
		return userValuations
	}

	// Create sortable holder list
	holders, sum := buildUserHolders(filtered, earliestBets)

	// Apply delta correction
	adjusted := adjustValuations(filtered, holders, sum, targetMarketVolume)

	return adjusted
}

// filterWinningValuations drops users with zero rounded value
func filterWinningValuations(all map[string]UserValuationResult) map[string]UserValuationResult {
	filtered := make(map[string]UserValuationResult)
	for username, val := range all {
		if val.RoundedValue > 0 {
			filtered[username] = val
		}
	}
	return filtered
}

// buildUserHolders prepares sorted holders and computes total value sum
func buildUserHolders(
	userVals map[string]UserValuationResult,
	earliest map[string]time.Time,
) ([]UserHolder, int64) {
	var (
		holders []UserHolder
		sum     int64
	)
	for username, val := range userVals {
		sum += val.RoundedValue
		earliestTime := earliest[username]
		holders = append(holders, UserHolder{
			Username:     username,
			RoundedValue: val.RoundedValue,
			EarliestBet:  earliestTime,
		})
	}
	sort.Sort(ByValBetTimeUsername(holders))
	return holders, sum
}

// adjustValuations spreads rounding delta among holders
func adjustValuations(
	userVals map[string]UserValuationResult,
	holders []UserHolder,
	sum int64,
	target int64,
) map[string]UserValuationResult {
	delta := target - sum
	if delta == 0 {
		return userVals
	}

	adjustment := int64(1)
	if delta < 0 {
		adjustment = -1
		delta = -delta
	}

	holderCount := int64(len(holders))
	for i := int64(0); i < delta; i++ {
		holder := holders[i%holderCount]
		val := userVals[holder.Username]
		val.RoundedValue += adjustment
		userVals[holder.Username] = val
	}
	return userVals
}

package positionsmath

import (
	"socialpredict/models"
	"sort"
	"time"
)

// UserProfitability represents a user's profitability data for a specific market.
type UserProfitability struct {
	Username       string    `json:"username"`
	CurrentValue   int64     `json:"currentValue"`
	TotalSpent     int64     `json:"totalSpent"`
	Profit         int64     `json:"profit"`
	Position       string    `json:"position"` // "YES", "NO", "NEUTRAL"
	YesSharesOwned int64     `json:"yesSharesOwned"`
	NoSharesOwned  int64     `json:"noSharesOwned"`
	EarliestBet    time.Time `json:"earliestBet"`
	Rank           int       `json:"rank"`
}

// CalculateMarketLeaderboard ranks users in a market by profitability.
func CalculateMarketLeaderboard(snapshot MarketSnapshot, bets []models.Bet) ([]UserProfitability, error) {
	positions, err := CalculateMarketPositions_WPAM_DBPM(snapshot, bets)
	if err != nil {
		return nil, err
	}

	if len(bets) == 0 {
		return []UserProfitability{}, nil
	}

	var leaderboard []UserProfitability

	for _, position := range positions {
		if position.YesSharesOwned == 0 && position.NoSharesOwned == 0 {
			continue
		}

		totalSpent := CalculateUserSpend(bets, position.Username)
		profit := position.Value - totalSpent
		positionType := DeterminePositionType(position.YesSharesOwned, position.NoSharesOwned)
		earliestBet := GetEarliestBetTime(bets, position.Username)

		leaderboard = append(leaderboard, UserProfitability{
			Username:       position.Username,
			CurrentValue:   position.Value,
			TotalSpent:     totalSpent,
			Profit:         profit,
			Position:       positionType,
			YesSharesOwned: position.YesSharesOwned,
			NoSharesOwned:  position.NoSharesOwned,
			EarliestBet:    earliestBet,
		})
	}

	sort.Slice(leaderboard, func(i, j int) bool {
		if leaderboard[i].Profit == leaderboard[j].Profit {
			return leaderboard[i].EarliestBet.Before(leaderboard[j].EarliestBet)
		}
		return leaderboard[i].Profit > leaderboard[j].Profit
	})

	for i := range leaderboard {
		leaderboard[i].Rank = i + 1
	}

	return leaderboard, nil
}

// CalculateUserSpend sums a user's total spend (positive buys, negative sells).
func CalculateUserSpend(bets []models.Bet, username string) int64 {
	var total int64
	for _, bet := range bets {
		if bet.Username == username {
			total += bet.Amount
		}
	}
	return total
}

// GetEarliestBetTime returns the earliest bet timestamp for the user.
func GetEarliestBetTime(bets []models.Bet, username string) time.Time {
	var earliest time.Time
	first := true

	for _, bet := range bets {
		if bet.Username != username {
			continue
		}
		if first || bet.PlacedAt.Before(earliest) {
			earliest = bet.PlacedAt
			first = false
		}
	}

	return earliest
}

// DeterminePositionType identifies whether the user holds YES, NO, or both.
func DeterminePositionType(yesShares, noShares int64) string {
	switch {
	case yesShares > 0 && noShares == 0:
		return "YES"
	case noShares > 0 && yesShares == 0:
		return "NO"
	case yesShares > 0 && noShares > 0:
		return "NEUTRAL"
	default:
		return "NONE"
	}
}

package dbpm

import (
	"reflect"
	"socialpredict/internal/domain/math/probabilities/wpam"
	"socialpredict/models"
