		IsResolved       bool
		ResolutionResult string
		Expected         map[string]int64
	}{
		{
			Name: "Unresolved market, YES/NO users at 50%",
			UserPositions: []struct {
				Username       string
				YesSharesOwned int64
				NoSharesOwned  int64
			}{
				{"alice", 10, 0},
				{"bob", 0, 10},
			},
			Probability:      0.5,
			TotalVolume:      20,
			IsResolved:       false,
			ResolutionResult: "",
			Expected:         map[string]int64{"alice": 10, "bob": 10},
		},
		{
			Name: "Resolved market: YES wins",
			UserPositions: []struct {
				Username       string
				YesSharesOwned int64
				NoSharesOwned  int64
			}{
				{"alice", 10, 0},
				{"bob", 0, 10},
			},
			Probability:      0.5, // ignored if resolved
			TotalVolume:      20,
			IsResolved:       true,
			ResolutionResult: "YES",
			Expected:         map[string]int64{"alice": 20, "bob": 0},
		},
		{
			Name: "Resolved market: NO wins",
			UserPositions: []struct {
				Username       string
				YesSharesOwned int64
				NoSharesOwned  int64
			}{
				{"alice", 10, 0},
				{"bob", 0, 10},
			},
			Probability:      0.5, // ignored if resolved
			TotalVolume:      20,
			IsResolved:       true,
			ResolutionResult: "NO",
			Expected:         map[string]int64{"alice": 0, "bob": 20},
		},
		{
			Name: "Resolved market: All YES, NO wins (all get zero)",
			UserPositions: []struct {
				Username       string
				YesSharesOwned int64
				NoSharesOwned  int64
			}{
				{"alice", 10, 0},
				{"bob", 5, 0},
			},
			Probability:      0.8,
			TotalVolume:      15,
			IsResolved:       true,
			ResolutionResult: "NO",
			Expected:         map[string]int64{"alice": 0, "bob": 0},
		},
		{
			Name: "Resolved market: All NO, YES wins (all get zero)",
			UserPositions: []struct {
				Username       string
				YesSharesOwned int64
				NoSharesOwned  int64
			}{
				{"alice", 0, 10},
				{"bob", 0, 5},
			},
			Probability:      0.2,
			TotalVolume:      15,
			IsResolved:       true,
			ResolutionResult: "YES",
			Expected:         map[string]int64{"alice": 0, "bob": 0},
		},
	}

	for _, tc := range testcases {
		t.Run(tc.Name, func(t *testing.T) {
			positions := makeUserPositions(tc.UserPositions)
			earliest := make(map[string]time.Time)
			base := time.Now()
			for i, pos := range tc.UserPositions {
				earliest[pos.Username] = base.Add(time.Duration(i) * time.Minute)
			}

			actual, err := CalculateRoundedUserValuationsFromUserMarketPositions(
				positions,
				tc.Probability,
				tc.TotalVolume,
				tc.IsResolved,
				tc.ResolutionResult,
				earliest,
			)
			if err != nil {
				t.Fatalf("unexpected error: %v", err)
			}

			for user, want := range tc.Expected {
				got := actual[user].RoundedValue
				if got != want {
					t.Errorf("user %s: expected value %d, got %d", user, want, got)
				}
			}
		})
	}
}

package positionsmath

import (
	"testing"
	"time"
)

func TestAdjustUserValuationsToMarketVolume(t *testing.T) {
	// Users will have identical values, but alice's bet is earliest, then bob, then carol
	userBetOffsets := map[string]time.Duration{
		"alice": 0,
		"bob":   1 * time.Minute,
		"carol": 2 * time.Minute,
	}

	earliest := make(map[string]time.Time)
	base := time.Now()
	for user, offset := range userBetOffsets {
		earliest[user] = base.Add(offset)
	}

	// All users have a rounded value of 10
	userVals := map[string]UserValuationResult{
		"alice": {Username: "alice", RoundedValue: 10},
		"bob":   {Username: "bob", RoundedValue: 10},
		"carol": {Username: "carol", RoundedValue: 10},
	}

	// Delta: need to add 2 (should go to alice then bob, since they are first by earliest bet)
	targetVolume := int64(32)
	adjusted := AdjustUserValuationsToMarketVolume(userVals, earliest, targetVolume)
	want := map[string]int64{"alice": 11, "bob": 11, "carol": 10}
	for user, exp := range want {
		if adjusted[user].RoundedValue != exp {
			t.Errorf("user %s: want %d, got %d", user, exp, adjusted[user].RoundedValue)
		}
	}
	// Check total
	var sum int64
	for _, v := range adjusted {
		sum += v.RoundedValue
	}
	if sum != targetVolume {
		t.Errorf("expected total %d, got %d", targetVolume, sum)
	}

	// Test negative delta (removes from alice then bob)
	userVals = map[string]UserValuationResult{
		"alice": {Username: "alice", RoundedValue: 10},
		"bob":   {Username: "bob", RoundedValue: 10},
		"carol": {Username: "carol", RoundedValue: 10},
	}
	targetVolume = int64(28) // Remove 2
	adjusted = AdjustUserValuationsToMarketVolume(userVals, earliest, targetVolume)
	want = map[string]int64{"alice": 9, "bob": 9, "carol": 10}
	for user, exp := range want {
		if adjusted[user].RoundedValue != exp {
			t.Errorf("user %s: want %d, got %d", user, exp, adjusted[user].RoundedValue)
		}
	}
}

